qss:
QWidget { background: #071820; color: #e2f6ff; font-family: Segoe UI, Arial, sans-serif; font-size: 10pt; }
QMainWindow, QDialog { background: #071820; }
QGroupBox { background: #0d2633; border: 1px solid #1d5a73; border-radius: 8px; margin-top: 12px; padding: 10px; font-weight: bold; }
QGroupBox::title { subcontrol-origin: margin; left: 12px; padding: 0 4px; color: #00a7c7; }
QTabWidget::pane { border: 1px solid #1d5a73; background: #0d2633; }
QTabBar::tab { background: #061219; color: #e2f6ff; padding: 8px 14px; border: 1px solid #1d5a73; border-bottom: none; min-width: 100px; }
QTabBar::tab:selected { background: #007997; color: #eaffff; font-weight: bold; }
QTabBar::tab:hover { background: #123d52; color: #eaffff; }
QPushButton { background: #123d52; color: #eaffff; border: 1px solid #00a7c7; border-radius: 6px; padding: 7px 12px; font-weight: 600; }
QPushButton:hover { background: #00a7c7; color: #eaffff; }
QPushButton:disabled { background: #426170; color: #061219; border-color: #1d5a73; }
QLineEdit, QTextEdit, QTextBrowser, QPlainTextEdit, QComboBox, QSpinBox, QDoubleSpinBox { background: #061219; color: #e2f6ff; border: 1px solid #1d5a73; border-radius: 5px; padding: 5px; selection-background-color: #00a7c7; selection-color: #eaffff; }
QComboBox QAbstractItemView { background: #061219; color: #e2f6ff; selection-background-color: #00a7c7; selection-color: #eaffff; border: 1px solid #1d5a73; }
QTableWidget { background: #061219; alternate-background-color: #0d2633; color: #e2f6ff; gridline-color: #1d5a73; selection-background-color: #00a7c7; selection-color: #eaffff; }
QHeaderView::section { background: #007997; color: #eaffff; padding: 6px; border: 1px solid #1d5a73; font-weight: bold; }
QScrollBar:vertical { background: #0d2633; width: 14px; }
QScrollBar::handle:vertical { background: #00a7c7; border-radius: 6px; min-height: 24px; }
QScrollBar:horizontal { background: #0d2633; height: 14px; }
QScrollBar::handle:horizontal { background: #00a7c7; border-radius: 6px; min-width: 24px; }
QCheckBox { spacing: 6px; }
QLabel { color: #e2f6ff; }
